+
+impl Drop for PhaseBudgetGuard {
+    fn drop(&mut self) {
+        if !self.restore_original {
+            return;
+        }
+
+        let Ok(mut guard) = self.inner.write() else {
+            return;
+        };
+
+        let phase_remaining = guard.budget;
+        let polls_used = self
